"use client";

import { FadeIn } from "@/components/FadeIn";
import { Button } from "@/components/Button";
import { useState } from "react";
import { ChevronDown, Truck, RotateCcw } from "lucide-react";
import { useCart } from "@/components/CartProvider";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { saveCheckoutIntent } from "@/lib/checkout-intent";
import { SmartImage } from "@/components/SmartImage";

export default function ProductClient({ product }: { product: any }) {
    const { addToCart } = useCart();
    const { data: session } = useSession();
    const router = useRouter();
    const [activeTab, setActiveTab] = useState("specs");

    let parsedImages: string[] = [];
    try {
        if (typeof product.images === "string") {
            parsedImages = JSON.parse(product.images);
        } else if (Array.isArray(product.images)) {
            parsedImages = product.images;
        }
    } catch (e) {
        console.log("Error parsing images in product details", e);
    }
    const images = parsedImages.length > 0 ? parsedImages : [];

    const viewOptions = ["Image Gallery"];
    const [viewMode, setViewMode] = useState("Image Gallery");
    const [activeImage, setActiveImage] = useState(images.length > 0 ? images[0] : "");
    const imageFallbackType = product.category?.name?.toLowerCase().includes("diamond")
        ? "diamond"
        : product.category?.name?.toLowerCase().includes("ring")
            ? "ring"
            : "jewelry";

    const handleAddToCart = () => {
        addToCart({
            id: product.id,
            name: product.name,
            price: product.price,
            quantity: 1,
            image: images.length > 0 ? images[0] : ""
        });
    };

    const handleBuyNow = () => {
        const item = {
            id: product.id,
            name: product.name,
            price: product.price,
            quantity: 1,
            image: images.length > 0 ? images[0] : "",
        };

        if (!session?.user) {
            saveCheckoutIntent({
                source: "single-product",
                item,
                createdAt: Date.now(),
            });
            router.push("/login?redirect=/checkout&message=checkout_required");
            return;
