                                        <button
                                            key={i}
                                            onClick={() => setActiveImage(img)}
                                            className={`w-[100px] h-[100px] shrink-0 relative rounded-none overflow-hidden transition-all duration-300 premium-card ${activeImage === img ? "ring-2 ring-black/70 opacity-100" : "opacity-70 hover:opacity-100"}`}
                                        >
                                            <SmartImage src={img} alt="thumbnail" fill fallbackType={imageFallbackType as any} className="object-cover" />
                                        </button>
                                    ))}
                                </FadeIn>
                            )}
                        </>
                    )}
                </section>

                {/* Right: Details (Scrollable Flow) */}
                <section className="flex-1 lg:max-w-[45%] pt-4 flex flex-col">
                    <FadeIn delay={0.2}>
                        <p className="section-kicker mb-4">Product Detail</p>
                        <h1 className="section-title max-w-xl mb-6">
                            {product.name}
                        </h1>

                        <div className="flex items-baseline gap-6 mb-8 border-b border-black/10 pb-8">
                            <span className="text-4xl font-bold font-body text-black">₹{product.price.toLocaleString("en-IN")}</span>
                            <span className="text-xs uppercase tracking-[0.24em] text-black/50 font-medium">Inclusive of all taxes</span>
                        </div>

                        <p className="section-copy mb-12 font-body font-light">
                            {product.description}
                        </p>

                        {/* Selectors */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="w-full">
                                <label className="block text-sm uppercase tracking-[0.24em] text-black/70 mb-3 font-medium">Select Metal</label>
                                <div className="relative">
                                    <select className="w-full p-5 rounded-none border border-black/10 bg-white/80 text-black appearance-none focus:outline-none focus:border-black transition-colors cursor-pointer shadow-sm font-medium">
                                        <option>{product.metalType}</option>
                                        <option>18K Yellow Gold</option>
                                        <option>18K Rose Gold</option>
                                        <option>Platinum 950</option>
                                    </select>
                                    <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-champagne-text pointer-events-none" size={18} />
                                </div>
                            </div>
                        </div>

                        {/* Delivery Info */}
                        <div className="flex items-center gap-5 premium-panel p-6 mb-12 relative overflow-hidden">
                            <div className="absolute right-0 top-0 w-32 h-full bg-gradient-to-l from-white/70 to-transparent pointer-events-none" />
                            <div className="w-12 h-12 rounded-full border border-black/10 flex items-center justify-center shrink-0 bg-white">
                                <Truck className="text-black" size={20} strokeWidth={1.5} />
                            </div>
                            <span className="text-[0.95rem] text-black/75 leading-snug font-light">
                                <strong className="block text-black tracking-wide font-medium mb-1 uppercase text-sm">Guaranteed Delivery</strong>
                                Delivered within 7-10 working days across India via insured shipping.
                            </span>
                        </div>

                        {/* Sticky Add to Cart Actions */}
                        <div className="flex flex-col gap-5 sticky bottom-10 z-40 premium-panel p-6">
                            <Button fullWidth onClick={handleAddToCart} className="py-5 shadow-xl text-[1rem]">
                                Add to Cart
                            </Button>
                            <Button variant="outline" fullWidth onClick={handleBuyNow} className="border-black text-black hover:bg-black hover:text-white py-5 text-[1rem]">
                                Buy Now
                            </Button>
                            <Button variant="outline" fullWidth className="border-black text-black hover:bg-black hover:text-white">
                                Book Video Consultation
                            </Button>
                        </div>
                    </FadeIn>
                </section>
            </div>

            {/* Product Specifications & Details Tabs */}
            <section className="max-w-[1100px] mx-auto pt-16 border-t border-black/10 px-5">
                <FadeIn>
                    <div className="flex justify-center gap-12 border-b border-black/10 mb-16">
                        <button
                            onClick={() => setActiveTab("specs")}
                            className={`pb-5 text-xl font-heading tracking-wide transition-colors relative ${activeTab === "specs" ? "text-black" : "text-black/40 hover:text-black/80"} ${activeTab === "specs" ? "after:absolute after:bottom-[-1px] after:left-0 after:w-full after:h-[2px] after:bg-black" : ""}`}
                        >
                            Product Specifications
                        </button>
                        <button
                            onClick={() => setActiveTab("reviews")}
                            className={`pb-5 text-xl font-heading tracking-wide transition-colors relative ${activeTab === "reviews" ? "text-black" : "text-black/40 hover:text-black/80"} ${activeTab === "reviews" ? "after:absolute after:bottom-[-1px] after:left-0 after:w-full after:h-[2px] after:bg-black" : ""}`}
