                                    <h4 className="text-2xl text-black mb-3 font-heading tracking-wide">Absolutely Stunning</h4>
                                    <p className="text-black/75 mb-4 leading-relaxed font-light">The ring is even more beautiful in person. The craftsmanship is flawless, and the diamond sparkles incredibly.</p>
                                    <p className="text-sm text-black/55 uppercase tracking-widest font-medium">Anjali S. — October 12, 2023</p>
                                </div>

                                <div className="mt-10">
                                    <ReviewForm productId={product.id} />
                                </div>
                            </div>
                        )}
                    </div>
                </FadeIn>
            </section>
        </div>
    );
}

function ReviewForm({ productId }: { productId: string }) {
    const { data: session } = useSession();
    const [rating, setRating] = useState(5);
    const [comment, setComment] = useState("");
    const [isSubmitting, setIsSubmitting] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);
        try {
            await fetch('/api/reviews', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ productId, rating, comment })
            });
            alert("Review submitted successfully");
            setComment("");
        } catch (err) {
            console.error(err);
        } finally {
            setIsSubmitting(false);
        }
    };

    if (!session) {
        return <div className="mt-12 py-8 border-t border-black/10 text-black/60 tracking-widest uppercase text-base text-center font-medium">Please login to write a review.</div>;
    }

    return (
        <form onSubmit={handleSubmit} className="mt-12 pt-10 border-t border-black/10 text-left max-w-[600px] mx-auto">
            <h4 className="text-2xl font-heading text-black mb-8">Write a Review</h4>
            <div className="mb-6">
                <label className="block text-sm uppercase tracking-widest text-black/70 mb-3 font-medium">Rating</label>
                <select value={rating} onChange={(e) => setRating(Number(e.target.value))} className="w-full max-w-[200px] p-4 rounded-none border border-champagne-accent/30 text-champagne-text appearance-none bg-[#F4F1E9] focus:outline-none focus:border-champagne-text transition-colors cursor-pointer font-medium">
                    <option value="5">5 Stars</option>
                    <option value="4">4 Stars</option>
                    <option value="3">3 Stars</option>
                    <option value="2">2 Stars</option>
                    <option value="1">1 Star</option>
                </select>
            </div>
            <div className="mb-8">
                <label className="block text-sm uppercase tracking-widest text-champagne-text/80 mb-3 font-medium">Review</label>
                <textarea
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                    rows={5}
                    className="w-full p-5 rounded-none border border-black/10 bg-white/80 text-black focus:outline-none focus:border-black transition-colors resize-none placeholder:text-black/30"
                    placeholder="Share your experience..."
                />
            </div>
            <Button disabled={isSubmitting} className="w-full md:w-auto">{isSubmitting ? "Submitting..." : "Submit Review"}</Button>
        </form>
    );
}

function StarIcon() {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-full h-full">
            <path fillRule="evenodd" d="M10.788 3.21c.448-1.077 1.976-1.077 2.424 0l2.082 5.006 5.404.434c1.164.093 1.636 1.545.749 2.305l-4.117 3.527 1.257 5.273c.271 1.136-.964 2.033-1.96 1.425L12 18.354 7.373 21.18c-.996.608-2.231-.29-1.96-1.425l1.257-5.273-4.117-3.527c-.887-.76-.415-2.212.749-2.305l5.404-.434 2.082-5.005Z" clipRule="evenodd" />
        </svg>
    );
}

