"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { signOut, useSession } from "next-auth/react";
import Image from "next/image";
import { LayoutDashboard, Gem, Settings2, ShoppingBag, Users, LogOut, BarChart, Menu, X } from "lucide-react";
import { useEffect, useState } from "react";

const adminNav = [
    { name: "Dashboard", href: "/admin", icon: LayoutDashboard },
    { name: "Diamonds", href: "/admin/diamonds", icon: Gem },
    { name: "Ring Settings", href: "/admin/ring-settings", icon: Settings2 },
    { name: "Products", href: "/admin/products", icon: Gem },
    { name: "Orders", href: "/admin/orders", icon: ShoppingBag },
    { name: "Users", href: "/admin/users", icon: Users },
    { name: "Analytics", href: "/admin/analytics", icon: BarChart },
];

export default function AdminLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const { data: session, status } = useSession();
    const [mobileNavOpen, setMobileNavOpen] = useState(false);

    useEffect(() => {
        setMobileNavOpen(false);
    }, [pathname]);

    if (status === "loading") {
        return <div className="min-h-screen flex items-center justify-center text-black/60 font-body">Loading secure portal...</div>;
    }

    if (!session || session.user.role !== "ADMIN") {
        return <div className="min-h-screen flex items-center justify-center text-red-600 font-body">Access Denied. Admins Only.</div>;
    }

    const currentRouteName = adminNav.find(item => item.href === pathname)?.name || "Admin Panel";

    return (
        <div className="flex h-screen overflow-hidden font-body text-[#151922]">
            {mobileNavOpen && (
                <button
                    onClick={() => setMobileNavOpen(false)}
                    className="fixed inset-0 z-20 bg-black/40 lg:hidden"
                    aria-label="Close menu"
                />
            )}
            {/* Sidebar Navigation */}
            <aside className={`fixed lg:static inset-y-0 left-0 w-72 lg:w-64 premium-panel flex flex-col flex-shrink-0 z-30 transition-transform duration-300 ${mobileNavOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"}`}>
                {/* Brand Area */}
                <div className="h-20 flex flex-col justify-center items-center border-b border-black/10">
                    <Link href="/admin" className="text-xl font-heading text-[#111111] tracking-[0.2em] flex flex-col items-center">
                        <Image src="/assets/logo.png" alt="ZYNORA LUXE" width={100} height={30} className="object-contain" />
                    </Link>
                </div>

                {/* Navigation Links */}
                <nav className="flex-1 overflow-y-auto py-8 px-5 flex flex-col gap-2 custom-scrollbar">
                    {adminNav.map((item) => {
                        const isActive = pathname === item.href || (pathname.startsWith(item.href) && item.href !== "/admin");
                        return (
                            <Link
                                key={item.name}
                                href={item.href}
                                className={`flex items-center gap-4 px-4 py-3.5 rounded-none transition-all duration-300 ${isActive
                                    ? "bg-black text-white font-bold shadow-md"
                                    : "text-black/55 hover:bg-black/5 hover:text-black"
                                    }`}
                            >
                                <item.icon size={20} className={isActive ? "text-white" : "text-black/35"} />
                                <span className="text-[0.9rem] tracking-widest uppercase">{item.name}</span>
                            </Link>
                        );
                    })}
                </nav>

                {/* Bottom Logout Area */}
                <div className="p-5 border-t border-black/10 bg-black/[0.02]">
                    <button
                        onClick={() => signOut({ callbackUrl: '/' })}
                        className="w-full flex items-center justify-center gap-3 px-4 py-3.5 text-xs uppercase tracking-widest font-bold text-black/55 rounded-none hover:bg-red-50 hover:text-red-600 border border-transparent hover:border-red-200 transition-all"
                    >
                        <LogOut size={16} />
                        Secure Logout
                    </button>
                    <div className="text-center mt-5 mb-2">
                        <Link href="/" className="text-[10px] text-black/40 hover:text-black transition-colors uppercase tracking-[0.2em]">➔ Back to Store</Link>
                    </div>
                </div>
            </aside>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col min-w-0 overflow-hidden relative">
                {/* Background Details */}
                <div className="absolute inset-0 bg-gradient-to-br from-white via-transparent to-transparent pointer-events-none z-0" />

                {/* Top Admin Header */}
                <header className="h-20 bg-white/85 backdrop-blur-md border-b border-black/10 flex items-center justify-between px-10 flex-shrink-0 shadow-sm z-10 sticky top-0">
                    <div className="flex items-center gap-3">
                        <button
                            className="lg:hidden p-2 text-black/55 hover:text-black"
                            onClick={() => setMobileNavOpen((v) => !v)}
                            aria-label="Toggle admin navigation"
                        >
                            {mobileNavOpen ? <X size={20} /> : <Menu size={20} />}
                        </button>
                        <h1 className="text-xl md:text-2xl font-heading text-[#111111] font-semibold tracking-wide">{currentRouteName}</h1>
                    </div>

                    <div className="flex items-center gap-6">
                        <div className="flex items-center gap-4 border-r border-black/10 pr-6">
                            <div className="w-10 h-10 rounded-full bg-black/5 flex items-center justify-center text-[#111111] font-bold text-sm uppercase border border-black/10 shadow-sm">
                                {session.user.name?.[0] || 'A'}
                            </div>
                            <div className="hidden md:block">
                                <p className="text-sm font-bold tracking-wide text-[#111111]">{session.user.name}</p>
                                <p className="text-[10px] text-black/50 uppercase tracking-widest mt-0.5">{session.user.email}</p>
                            </div>
                        </div>
                        <button
                            onClick={() => signOut({ callbackUrl: '/' })}
                            className="p-2.5 text-black/35 hover:text-red-500 hover:bg-black/5 rounded-none transition-all"
                            title="Logout"
                        >
                            <LogOut size={20} />
                        </button>
                    </div>
                </header>

                {/* Scrollable Content Pane */}
                <main className="flex-1 overflow-y-auto p-4 sm:p-6 md:p-10 custom-scrollbar z-10">
                    <div className="max-w-7xl mx-auto">
                        {children}
                    </div>
                </main>
            </div>
        </div>
    );
}

import { NextResponse } from "next/server";
import { PrismaClient } from "@prisma/client";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";

const prisma = new PrismaClient();

// Toggle existing Diamond Stock Status
export async function PATCH(req: Request, { params }: { params: Promise<{ id: string }> }) {
    try {
        const { id } = await params;
        const session = await getServerSession(authOptions);
        if (!session || session.user.role !== "ADMIN") return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

        const body = await req.json();

        const updateData: any = {};
        if (body.stockStatus !== undefined) updateData.stockStatus = body.stockStatus;
        if (body.shape !== undefined) updateData.shape = body.shape;
        if (body.caratWeight !== undefined) updateData.caratWeight = parseFloat(body.caratWeight);
        if (body.cut !== undefined) updateData.cut = body.cut;
        if (body.clarity !== undefined) updateData.clarity = body.clarity;
        if (body.color !== undefined) updateData.color = body.color;
        if (body.certification !== undefined) updateData.certification = body.certification;
        if (body.price !== undefined) updateData.price = parseFloat(body.price);
        if (body.imageUrl !== undefined) updateData.imageUrl = body.imageUrl;
        if (body.modelUrl !== undefined) updateData.modelUrl = body.modelUrl;

        const diamond = await prisma.diamond.update({
            where: { id },
            data: updateData,
        });

        return NextResponse.json({ success: true, diamond });
    } catch (e) {
        return NextResponse.json({ error: "Internal Error" }, { status: 500 });
    }
}

export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
    try {
        const { id } = await params;
        console.log("[API] DELETE /api/admin/diamonds/[id] called with id:", id);
        const session = await getServerSession(authOptions);
        if (!session || session.user.role !== "ADMIN") {
            console.log("[API] DELETE diamond unauthorized");
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        // First delete related OrderItems that reference RingConfigurations using this diamond
        const configs = await prisma.ringConfiguration.findMany({
            where: { diamondId: id },
            select: { id: true }
        });
        
        if (configs.length > 0) {
            const configIds = configs.map(c => c.id);
            // Delete order items linked to these configurations
            await prisma.orderItem.deleteMany({
                where: { ringConfigurationId: { in: configIds } }
            });
            // Delete the configurations themselves
            await prisma.ringConfiguration.deleteMany({
                where: { diamondId: id }
            });
        }

        // Now delete the diamond
        await prisma.diamond.delete({ where: { id } });
        console.log("[API] Diamond deleted successfully:", id);
        return NextResponse.json({ success: true });
    } catch (e: any) {
        console.error("[API] DELETE diamond error:", e);
        return NextResponse.json({ error: "Failed to delete diamond: " + (e.message || "Internal Error") }, { status: 500 });
    }
}

